// apiKeyStatusClass maps a status value to its badge color, with a default
// for any value outside the four domain.APIKeyStatus constants — this
// template must never fail to render just because a future status is added
// to the domain before this mapping is updated.
func apiKeyStatusClass(status string) string {
	switch status {
	case "current":
		return "bg-green-50 text-green-700"
	case "retiring":
		return "bg-amber-50 text-amber-700"
	case "expired":
		return "bg-slate-100 text-slate-500"
	case "revoked":
		return "bg-red-50 text-red-600"
	default:
		return "bg-slate-100 text-slate-500"
	}
}

